sourcesContent:
import React, { useState, useEffect, useCallback, useRef } from 'react';
import './PoeticSnakeGame.css';

interface Position {
  x: number;
  y: number;
}

interface WordItem {
  word: string;
  x: number;
  y: number;
  type: 'normal' | 'magic';
  theme?: string;
}

interface CollectedWord {
  word: string;
  poeticAssociation: string;
  imageUrl?: string;
  type: 'normal' | 'magic';
}

interface Theme {
  name: string;
  description: string;
  words: string[];
  magicWords: string[];
  style: string;
  bgColor: string;
}

interface PoemLine {
  line: string;
  imageUrl?: string;
  word: string;
}

type GameState = 'MENU' | 'THEME_SELECT' | 'PLAYING' | 'POEM_SHOW' | 'IMAGE_SHOW' | 'GAME_OVER';
type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';

const GRID_SIZE = 20;
const CELL_SIZE = 28;
const WORDS_TO_COLLECT = 8;

const THEMES: Theme[] = [
  {
    name: '童话森林',
    description: '在魔法森林中收集单词，创作属于你的童话诗',
    words: ['树', '花', '鸟', '风', '雨', '云', '山', '河', '星', '月', '草', '石'],
    magicWords: ['精灵', '魔法', '城堡', '龙'],
    style: '童话风格，色彩缤纷，梦幻',
    bgColor: '#2d5016'
  },
  {
    name: '科幻未来',
    description: '在星际间探索，用科技词汇谱写未来诗篇',
    words: ['光', '电', '星', '空', '梦', '想', '飞', '航', '宇', '宙', '机', '人'],
    magicWords: ['黑洞', '量子', '时空', '银河'],
    style: '科幻风格，赛博朋克，未来感',
    bgColor: '#1a1a3e'
  },
  {
    name: '唐诗意境',
    description: '追寻古人的足迹，用现代视角重新诠释诗意',
    words: ['春', '秋', '花', '月', '山', '水', '风', '雨', '雪', '霜', '柳', '梅'],
    magicWords: ['江南', '长安', '琵琶', '丹青'],
    style: '中国水墨画风格，意境深远',
    bgColor: '#3e2723'
  },
  {
    name: '海洋探险',
    description: '潜入深海，收集海洋生物的词汇宝藏',
    words: ['海', '浪', '鱼', '鲸', '沙', '贝', '礁', '潮', '帆', '港', '岛', '湾'],
    magicWords: ['珊瑚', '珍珠', '海神', '宝藏'],
    style: '海洋风格，蓝色调，神秘深邃',
    bgColor: '#0d47a1'
  }
];

const POETIC_ASSOCIATIONS: Record<string, string[]> = {
  '树': ['森林的守护者', '绿荫下的梦', '岁月的见证'],
  '花': ['春天的信使', '绽放的诗篇', '芬芳的记忆'],
  '鸟': ['天空的歌者', '自由的翅膀', '晨曦的问候'],
  '风': ['自然的呼吸', '远方的呼唤', '无形的诗人'],
