// 模拟AI生成诗歌
const generatePoem = (words: CollectedWord[], theme: Theme): string[] => {
  const lines: string[] = [];
  const themeIntro = `${theme.name}的诗篇`;
  lines.push(themeIntro);
  lines.push('');

  words.forEach((word, index) => {
    const association = word.poeticAssociation;
    const templates = [
      `${word.word}啊，你是${association}`,
      `在${theme.name}中，${word.word}化作了${association}`,
      `${association}，那是${word.word}的呼唤`,
      `${word.word}——${association}，如此美丽`,
      `当${word.word}遇见${theme.name}，便有了${association}`
    ];
    lines.push(templates[index % templates.length]);

    if (word.type === 'magic') {
      const magicEffect = MAGIC_EFFECTS[word.word];
      if (magicEffect) {
        lines.push(`  ✨ ${magicEffect.effect}`);
      }
    }
  });

  lines.push('');
  lines.push('—— 由蛇蛇诗人创作');

  return lines;
};

// 模拟AI生成图像URL（使用占位符）
const generateImageUrl = (word: string, theme: Theme): string => {
  const encodedWord = encodeURIComponent(`${word} ${theme.style}`);
  return `https://image.pollinations.ai/prompt/${encodedWord}?width=512&height=512&nologo=true`;
};

const PoeticSnakeGame: React.FC = () => {
  const [snake, setSnake] = useState<Position[]>([{ x: 10, y: 10 }]);
  const [direction, setDirection] = useState<Direction>('RIGHT');
  const [nextDirection, setNextDirection] = useState<Direction>('RIGHT');
  const [gameState, setGameState] = useState<GameState>('MENU');
  const [selectedTheme, setSelectedTheme] = useState<Theme>(THEMES[0]);
  const [words, setWords] = useState<WordItem[]>([]);
  const [collectedWords, setCollectedWords] = useState<CollectedWord[]>([]);
  const [poem, setPoem] = useState<string[]>([]);
  const [poemImages, setPoemImages] = useState<PoemLine[]>([]);
  const [score, setScore] = useState(0);
  const [magicEffects, setMagicEffects] = useState<string[]>([]);
  const [currentBgColor, setCurrentBgColor] = useState(THEMES[0].bgColor);
  const [showRemix, setShowRemix] = useState(false);
  const [remixedPoem, setRemixedPoem] = useState<string[]>([]);
  const [finalImage, setFinalImage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const gameLoopRef = useRef<NodeJS.Timeout | null>(null);
  const speedRef = useRef(200);

  const generateRandomWord = useCallback((currentSnake: Position[], currentWords: WordItem[]): WordItem => {
    const isMagic = Math.random() < 0.15; // 15%概率生成魔法单词
    const wordPool = isMagic ? selectedTheme.magicWords : selectedTheme.words;
    const availableWords = wordPool.filter(w => !currentWords.some(cw => cw.word === w) && !collectedWords.some(cw => cw.word === w));

    if (availableWords.length === 0) {
      // 如果单词都用完了，从所有主题中随机选择
      const allWords = [...selectedTheme.words, ...selectedTheme.magicWords];
      const word = allWords[Math.floor(Math.random() * allWords.length)];
      let newPos: Position;
      do {
        newPos = {
          x: Math.floor(Math.random() * GRID_SIZE),
          y: Math.floor(Math.random() * GRID_SIZE)
        };
      } while (currentSnake.some(s => s.x === newPos.x && s.y === newPos.y) || currentWords.some(w => w.x === newPos.x && w.y === newPos.y));

      return { word, x: newPos.x, y: newPos.y, type: isMagic ? 'magic' : 'normal' };
    }

    const word = availableWords[Math.floor(Math.random() * availableWords.length)];
    let newPos: Position;
    do {
      newPos = {
        x: Math.floor(Math.random() * GRID_SIZE),
        y: Math.floor(Math.random() * GRID_SIZE)
      };
    } while (currentSnake.some(s => s.x === newPos.x && s.y === newPos.y) || currentWords.some(w => w.x === newPos.x && w.y === newPos.y));

    return { word, x: newPos.x, y: newPos.y, type: isMagic ? 'magic' : 'normal' };
  }, [selectedTheme, collectedWords]);

  const initializeWords = useCallback((currentSnake: Position[]) => {
    const newWords: WordItem[] = [];
    for (let i = 0; i < 3; i++) {
      newWords.push(generateRandomWord(currentSnake, newWords));
    }
    setWords(newWords);
  }, [generateRandomWord]);

  const resetGame = useCallback(() => {
    const initialSnake = [{ x: 10, y: 10 }];
    setSnake(initialSnake);
    setDirection('RIGHT');
    setNextDirection('RIGHT');
    setCollectedWords([]);
    setWords([]);
    setPoem([]);
    setPoemImages([]);
    setScore(0);
    setMagicEffects([]);
    setCurrentBgColor(selectedTheme.bgColor);
    setShowRemix(false);
    setRemixedPoem([]);
    setFinalImage('');
    initializeWords(initialSnake);
    setGameState('PLAYING');
  }, [selectedTheme, initializeWords]);

  const checkCollision = useCallback((head: Position, body: Position[]): boolean => {
    if (head.x < 0 || head.x >= GRID_SIZE || head.y < 0 || head.y >= GRID_SIZE) {
      return true;
    }
    return body.some(segment => segment.x === head.x && segment.y === head.y);
  }, []);

  const moveSnake = useCallback(() => {
    setSnake(currentSnake => {
      const newDirection = nextDirection;
      setDirection(newDirection);

      const head = currentSnake[0];
      const newHead: Position = { ...head };

      switch (newDirection) {
        case 'UP': newHead.y -= 1; break;
        case 'DOWN': newHead.y += 1; break;
        case 'LEFT': newHead.x -= 1; break;
        case 'RIGHT': newHead.x += 1; break;
      }

      if (checkCollision(newHead, currentSnake)) {
        setGameState('GAME_OVER');
        return currentSnake;
      }

      const newSnake = [newHead, ...currentSnake];

      // 检查是否吃到单词
      const eatenWordIndex = words.findIndex(w => w.x === newHead.x && w.y === newHead.y);
      if (eatenWordIndex !== -1) {
        const eatenWord = words[eatenWordIndex];
        const associations = POETIC_ASSOCIATIONS[eatenWord.word] || ['美丽的意象'];
        const association = associations[Math.floor(Math.random() * associations.length)];

        const collectedWord: CollectedWord = {
          word: eatenWord.word,
          poeticAssociation: association,
          type: eatenWord.type
        };

        setCollectedWords(prev => {
          const newCollected = [...prev, collectedWord];

          // 检查是否收集够8个单词
          if (newCollected.length >= WORDS_TO_COLLECT) {
            setTimeout(() => {
              const generatedPoem = generatePoem(newCollected, selectedTheme);
              setPoem(generatedPoem);

              // 生成每个单词的图像
              const images: PoemLine[] = newCollected.map(w => ({
                line: w.poeticAssociation,
                imageUrl: generateImageUrl(w.word, selectedTheme),
                word: w.word
              }));
              setPoemImages(images);

              // 生成最终合成图像
              const finalImagePrompt = `${selectedTheme.name} 诗歌意境 ${newCollected.map(w => w.word).join(' ')}`;
              setFinalImage(generateImageUrl(finalImagePrompt, selectedTheme));

              setGameState('POEM_SHOW');
            }, 500);
          }

          return newCollected;
        });

        setScore(prev => prev + (eatenWord.type === 'magic' ? 20 : 10));

        // 处理魔法效果
        if (eatenWord.type === 'magic') {
          const magicEffect = MAGIC_EFFECTS[eatenWord.word];
          if (magicEffect) {
            setMagicEffects(prev => [...prev, magicEffect.effect]);
          }
        }

        // 生成新单词
        setWords(prev => {
          const remaining = prev.filter((_, i) => i !== eatenWordIndex);
          return [...remaining, generateRandomWord(newSnake, remaining)];
        });
      } else {
        newSnake.pop();
      }

      return newSnake;
    });
  }, [nextDirection, words, checkCollision, generateRandomWord, selectedTheme]);

  useEffect(() => {
    if (gameState === 'PLAYING') {
      gameLoopRef.current = setInterval(moveSnake, speedRef.current);
      return () => {
        if (gameLoopRef.current) clearInterval(gameLoopRef.current);
      };
    }
  }, [gameState, moveSnake]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (gameState !== 'PLAYING') return;

      switch (e.key) {
        case 'ArrowUp':
          e.preventDefault();
          if (direction !== 'DOWN') setNextDirection('UP');
          break;
        case 'ArrowDown':
          e.preventDefault();
          if (direction !== 'UP') setNextDirection('DOWN');
          break;
        case 'ArrowLeft':
          e.preventDefault();
          if (direction !== 'RIGHT') setNextDirection('LEFT');
          break;
        case 'ArrowRight':
          e.preventDefault();
          if (direction !== 'LEFT') setNextDirection('RIGHT');
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [gameState, direction]);

  // 绘制游戏画面
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // 背景
    ctx.fillStyle = currentBgColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 网格
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= GRID_SIZE; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL_SIZE, 0);
      ctx.lineTo(x * CELL_SIZE, GRID_SIZE * CELL_SIZE);
      ctx.stroke();
    }
    for (let y = 0; y <= GRID_SIZE; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL_SIZE);
      ctx.lineTo(GRID_SIZE * CELL_SIZE, y * CELL_SIZE);
      ctx.stroke();
    }

    // 绘制单词
    words.forEach(wordItem => {
      const x = wordItem.x * CELL_SIZE;
      const y = wordItem.y * CELL_SIZE;

      if (wordItem.type === 'magic') {
        // 魔法单词 - 发光效果
        ctx.shadowColor = '#ffd700';
        ctx.shadowBlur = 15;
        ctx.fillStyle = '#ffd700';
        ctx.fillRect(x + 2, y + 2, CELL_SIZE - 4, CELL_SIZE - 4);
        ctx.shadowBlur = 0;
      } else {
        ctx.fillStyle = '#ff6b6b';
        ctx.fillRect(x + 2, y + 2, CELL_SIZE - 4, CELL_SIZE - 4);
      }

      // 绘制文字
      ctx.fillStyle = '#fff';
      ctx.font = '12px Arial';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(wordItem.word, x + CELL_SIZE / 2, y + CELL_SIZE / 2);
    });

    // 绘制蛇
    snake.forEach((segment, index) => {
      const x = segment.x * CELL_SIZE;
      const y = segment.y * CELL_SIZE;

      if (index === 0) {
        ctx.fillStyle = '#4ecdc4';
        ctx.shadowColor = '#4ecdc4';
        ctx.shadowBlur = 10;
      } else {
        const opacity = Math.max(0.4, 1 - (index / snake.length) * 0.6);
        ctx.fillStyle = `rgba(78, 205, 196, ${opacity})`;
        ctx.shadowBlur = 0;
      }

      ctx.fillRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);
      ctx.shadowBlur = 0;

      // 蛇头眼睛
      if (index === 0) {
        ctx.fillStyle = '#fff';
        const eyeSize = 3;
        let eyeOffsetX = 0, eyeOffsetY = 0;

        switch (direction) {
          case 'UP': eyeOffsetX = 5; eyeOffsetY = 4; break;
          case 'DOWN': eyeOffsetX = 5; eyeOffsetY = 12; break;
          case 'LEFT': eyeOffsetX = 4; eyeOffsetY = 5; break;
          case 'RIGHT': eyeOffsetX = 12; eyeOffsetY = 5; break;
        }

        ctx.beginPath();
        ctx.arc(x + eyeOffsetX, y + eyeOffsetY, eyeSize, 0, Math.PI * 2);
        ctx.arc(x + eyeOffsetX + (direction === 'UP' || direction === 'DOWN' ? 8 : 0), 
                y + eyeOffsetY + (direction === 'LEFT' || direction === 'RIGHT' ? 8 : 0), eyeSize, 0, Math.PI * 2);
        ctx.fill();
      }
    });
  }, [snake, words, direction, currentBgColor]);

  const handleRemixPoem = () => {
    setIsGenerating(true);
    setTimeout(() => {
      const remixed = generatePoem(collectedWords, selectedTheme);
      setRemixedPoem(remixed);
      setShowRemix(true);
      setIsGenerating(false);
    }, 2000);
  };

  const handleShowImage = () => {
    setGameState('IMAGE_SHOW');
  };

  const handleShare = () => {
    const shareText = `我在${selectedTheme.name}中创作了一首诗！\n\n${poem.join('\n')}\n\n来试试你的创意吧！`;
    if (navigator.share) {
      navigator.share({
        title: '诗歌贪吃蛇 - AI创作',
        text: shareText
      });
    } else {
      navigator.clipboard.writeText(shareText);
      alert('诗歌已复制到剪贴板！');
    }
  };

  return (
    <div className="poetic-game-container">
      <div className="game-header">
        <h1 className="game-title">🐍 诗歌贪吃蛇</h1>
        <div className="score-board">
          <div className="score-item">
            <span className="score-label">收集单词</span>
            <span className="score-value">{collectedWords.length}/{WORDS_TO_COLLECT}</span>
          </div>
          <div className="score-item">
            <span className="score-label">得分</span>
            <span className="score-value">{score}</span>
          </div>
        </div>
      </div>

      {magicEffects.length > 0 && (
        <div className="magic-effects">
          {magicEffects.map((effect, index) => (
            <div key={index} className="magic-effect">✨ {effect}</div>
          ))}
        </div>
      )}

      <div className="game-board">
        <canvas
          ref={canvasRef}
          width={GRID_SIZE * CELL_SIZE}
          height={GRID_SIZE * CELL_SIZE}
          className="game-canvas"
        />

        {gameState === 'MENU' && (
          <div className="overlay">
            <div className="overlay-content">
              <h2>🐍 诗歌贪吃蛇</h2>
              <p>收集单词，创作诗歌，生成艺术</p>
              <p>吃够8个单词，AI将为你创作一首诗</p>
              <button className="btn btn-primary" onClick={() => setGameState('THEME_SELECT')}>
                选择主题
              </button>
            </div>
          </div>
        )}

        {gameState === 'THEME_SELECT' && (
          <div className="overlay theme-select">
            <div className="overlay-content">
              <h2>选择你的创作主题</h2>
              <div className="theme-grid">
                {THEMES.map((theme, index) => (
                  <div 
                    key={index} 
                    className="theme-card"
                    style={{ backgroundColor: theme.bgColor }}
                    onClick={() => {
                      setSelectedTheme(theme);
                      setCurrentBgColor(theme.bgColor);
                    }}
                  >
                    <h3>{theme.name}</h3>
                    <p>{theme.description}</p>
                    <div className="theme-words">
                      {theme.words.slice(0, 6).join('、')}...
                    </div>
                    {selectedTheme.name === theme.name && (
                      <div className="theme-selected">✓ 已选择</div>
                    )}
                  </div>
                ))}
              </div>
              <button className="btn btn-primary" onClick={resetGame}>
                开始创作
              </button>
            </div>
          </div>
        )}

        {gameState === 'POEM_SHOW' && (
          <div className="overlay poem-overlay">
            <div className="overlay-content poem-content">
              <h2>🎨 AI为你创作的诗</h2>
              <div className="poem-text">
                {showRemix && remixedPoem.length > 0 ? (
                  remixedPoem.map((line, index) => (
                    <p key={index} className="poem-line">{line}</p>
                  ))
                ) : (
                  poem.map((line, index) => (
                    <p key={index} className="poem-line">{line}</p>
                  ))
                )}
              </div>

              <div className="poem-images">
                {poemImages.map((item, index) => (
                  <div key={index} className="poem-image-item">
                    <img 
                      src={item.imageUrl} 
                      alt={item.word}
                      onError={(e) => {
                        (e.target as HTMLImageElement).src = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100"><rect width="100" height="100" fill="%23ddd"/><text x="50" y="50" text-anchor="middle" dy=".3em" fill="%23999">' + item.word + '</text></svg>';
                      }}
                    />
                    <span>{item.word}</span>
                  </div>
                ))}
              </div>

              <div className="poem-actions">
                <button 
                  className="btn btn-secondary" 
                  onClick={handleRemixPoem}
                  disabled={isGenerating}
                >
                  {isGenerating ? '✨ 重新混合中...' : '🎲 重新混合'}
                </button>
                <button className="btn btn-primary" onClick={handleShowImage}>
                  🎨 生成画作
                </button>
                <button className="btn btn-success" onClick={handleShare}>
                  📤 分享创作
                </button>
                <button className="btn btn-secondary" onClick={resetGame}>
                  🔄 再玩一次
                </button>
              </div>
            </div>
          </div>
        )}

        {gameState === 'IMAGE_SHOW' && (
          <div className="overlay image-overlay">
            <div className="overlay-content image-content">
              <h2>🎨 你的AI艺术作品</h2>
              <div className="final-image-container">
                <img 
                  src={finalImage} 
                  alt="AI生成的诗歌画作"
                  className="final-image"
                  onError={(e) => {
                    (e.target as HTMLImageElement).src = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="400"><rect width="400" height="400" fill="%23ddd"/><text x="200" y="200" text-anchor="middle" dy=".3em" fill="%23999">AI画作生成中...</text></svg>';
                  }}
                />
              </div>
              <div className="collected-words-summary">
                <h3>使用的单词：</h3>
                <div className="words-tags">
                  {collectedWords.map((word, index) => (
                    <span key={index} className={`word-tag ${word.type}`}>
                      {word.word}
                    </span>
                  ))}
                </div>
              </div>
              <div className="poem-actions">
                <button className="btn btn-secondary" onClick={() => setGameState('POEM_SHOW')}>
                  📜 返回诗歌
                </button>
                <button className="btn btn-success" onClick={handleShare}>
                  📤 分享创作
                </button>
                <button className="btn btn-primary" onClick={resetGame}>
                  🔄 再玩一次
                </button>
              </div>
            </div>
          </div>
        )}

        {gameState === 'GAME_OVER' && (
          <div className="overlay">
            <div className="overlay-content">
              <h2>游戏结束</h2>
              <p>你收集了 {collectedWords.length} 个单词</p>
              <p>得分: {score}</p>
              {collectedWords.length >= WORDS_TO_COLLECT ? (
                <button className="btn btn-primary" onClick={() => setGameState('POEM_SHOW')}>
                  查看诗歌
                </button>
              ) : (
                <button className="btn btn-primary" onClick={resetGame}>
                  再试一次
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="word-collection-box">
        <h3>📦 单词收集盒</h3>
        <div className="collected-words">
          {collectedWords.map((word, index) => (
            <div key={index} className={`collected-word ${word.type}`}>
              <span className="word-text">{word.word}</span>
              <span className="word-association">{word.poeticAssociation}</span>
            </div>
          ))}
          {Array.from({ length: WORDS_TO_COLLECT - collectedWords.length }).map((_, index) => (
            <div key={`empty-${index}`} className="collected-word empty">
              <span className="word-text">?</span>
            </div>
          ))}
        </div>
      </div>

      <div className="game-instructions">
        <p>⬆️ ⬇️ ⬅️ ➡️ 方向键移动 | 收集8个单词创作诗歌</p>
        <p>✨ 金色单词是魔法单词，有特殊效果！</p>
      </div>
    </div>
  );
};

export default PoeticSnakeGame;
